-- =============================================================================
-- R3ZON Business OS — Correcciones de Seguridad Críticas
-- =============================================================================

-- 1. Revocar acceso anon en v_equipo_negocio (expone auth.users)
revoke select on public.v_equipo_negocio from anon, public;

-- 2. Recrear vista v_equipo_negocio SIN SECURITY DEFINER
create or replace view public.v_equipo_negocio as
  select
    p.user_id              as user_id,
    coalesce(u.email, p.email_contacto) as email,
    coalesce(u.raw_user_meta_data->>'full_name', 'Titular') as nombre,
    'admin'::text          as rol,
    'activo'::text         as estado,
    true                   as es_owner,
    p.created_at           as invited_at,
    p.created_at           as accepted_at,
    p.id                   as negocio_id,
    null::uuid             as miembro_id
  from public.perfiles_negocio p
  left join auth.users u on u.id = p.user_id
  where p.user_id = auth.uid()

  union all

  select
    m.user_id,
    m.email,
    m.nombre,
    m.rol::text,
    m.estado::text,
    false as es_owner,
    m.invited_at,
    m.accepted_at,
    m.negocio_id,
    m.id as miembro_id
  from public.miembros_negocio m
  where exists (
    select 1 from public.perfiles_negocio p
     where p.id = m.negocio_id and p.user_id = auth.uid()
  );

grant select on public.v_equipo_negocio to authenticated;

-- 3. Revocar execute de anon en funciones SECURITY DEFINER existentes
revoke execute on function public.aceptar_invitacion(inet, text) from anon;
revoke execute on function public.clear_google_watch_channel() from anon;
revoke execute on function public.current_negocio_id() from anon;
revoke execute on function public.get_config_key(text, text) from anon;
revoke execute on function public.get_google_tokens() from anon;
revoke execute on function public.registrar_dispositivo(text, text, text, inet) from anon;
revoke execute on function public.registrar_onboarding(jsonb, inet, text) from anon;
revoke execute on function public.reordenar_tarea(uuid, text, integer) from anon;
revoke execute on function public.set_config_key(text, text, text, jsonb) from anon;
revoke execute on function public.set_google_sync_token(text) from anon;
revoke execute on function public.set_google_tokens(text, text, timestamptz, text, text) from anon;
revoke execute on function public.set_google_watch_channel(text, text, text, timestamptz) from anon;
revoke execute on function public.tg_create_perfil_on_signup() from anon;
revoke execute on function public.tg_seed_kanban_columnas() from anon;
revoke execute on function public.update_google_access_token(text, timestamptz) from anon;

-- 4. Añadir SET search_path = public a triggers (recomendable)
create or replace function public.tg_set_updated_at()
returns trigger language plpgsql security definer set search_path = public as $$
begin new.updated_at = now(); return new; end $$;

create or replace function public.tg_check_reports_to_same_cliente()
returns trigger language plpgsql security definer set search_path = public as $$
declare v_cliente uuid;
begin
  if new.reports_to is null then return new; end if;
  select cliente_id into v_cliente
    from public.contactos_cliente where id = new.reports_to;
  if v_cliente is null or v_cliente <> new.cliente_id then
    raise exception 'reports_to debe pertenecer al mismo cliente';
  end if;
  return new;
end $$;
