       and negocio_id = public.current_negocio_id();
  end loop;
end $$;"],"rollback":null},{"version":"20260512161219","name":"security_fix_rls_and_views","created_by":"alexhigueramartinez@gmail.com","idempotency_key":null,"statements":["
